import{_ as a,c as t,o as s,a1 as o}from"./chunks/framework.DDNAyvCW.js";const u=JSON.parse('{"title":"Asset Management","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/assets/index.md","filePath":"docs/mobile/assets/index.md"}'),i={name:"docs/mobile/assets/index.md"};function n(l,e,r,d,c,h){return s(),t("div",null,e[0]||(e[0]=[o('<h1 id="asset-management" tabindex="-1">Asset Management <a class="header-anchor" href="#asset-management" aria-label="Permalink to &quot;Asset Management&quot;">​</a></h1><p>The Assets module is the mobile entry point for managing SSH resources. It includes Direct Connections, Bastion Hosts, and Key Management.</p><h2 id="direct-connections" tabindex="-1">Direct Connections <a class="header-anchor" href="#direct-connections" aria-label="Permalink to &quot;Direct Connections&quot;">​</a></h2><p>Direct Connections are used for servers you add yourself.</p><h3 id="add-a-new-asset" tabindex="-1">Add a New Asset <a class="header-anchor" href="#add-a-new-asset" aria-label="Permalink to &quot;Add a New Asset&quot;">​</a></h3><ol><li>Tap the floating <code>+</code> button in the lower-right corner</li><li>Choose <code>New</code></li><li>Fill in the server information: <ul><li>Label</li><li>IP address or domain</li><li>Username</li><li>Port</li></ul></li><li>Choose an authentication method: <ul><li>Password</li><li>Private key</li></ul></li><li>Tap <code>Save</code></li></ol><h3 id="manage-assets" tabindex="-1">Manage Assets <a class="header-anchor" href="#manage-assets" aria-label="Permalink to &quot;Manage Assets&quot;">​</a></h3><ul><li>Connect: tap a host card to open an SSH session</li><li>Edit: long-press a card and choose <code>Edit</code></li><li>Favorite: long-press a card and choose <code>Favorite</code> to pin it near the top</li><li>Delete: long-press a card and choose <code>Delete</code></li></ul><h3 id="search-and-filter" tabindex="-1">Search and Filter <a class="header-anchor" href="#search-and-filter" aria-label="Permalink to &quot;Search and Filter&quot;">​</a></h3><p>You can search or filter by:</p><ul><li>Host name</li><li>IP address</li><li>Username</li><li>Group</li></ul><h2 id="bastion-hosts" tabindex="-1">Bastion Hosts <a class="header-anchor" href="#bastion-hosts" aria-label="Permalink to &quot;Bastion Hosts&quot;">​</a></h2><p>Bastion Hosts are used to manage server assets maintained behind a jump server.</p><h3 id="add-a-bastion-host" tabindex="-1">Add a Bastion Host <a class="header-anchor" href="#add-a-bastion-host" aria-label="Permalink to &quot;Add a Bastion Host&quot;">​</a></h3><ol><li>Tap <code>+</code></li><li>Choose <code>New</code></li><li>Fill in the bastion host name, address, port, and username</li><li>Choose key-based authentication</li><li>Tap <code>Save and Sync</code></li></ol><p>After saving, the synced server assets appear in the bastion host drop-down list.</p><h3 id="manage-bastion-hosts" tabindex="-1">Manage Bastion Hosts <a class="header-anchor" href="#manage-bastion-hosts" aria-label="Permalink to &quot;Manage Bastion Hosts&quot;">​</a></h3><ul><li>Sync assets: tap the sync button next to the group title</li><li>Edit: long-press the group name and choose <code>Edit</code></li><li>Delete: long-press the group name and choose <code>Delete</code></li></ul><h3 id="manage-synced-server-assets" tabindex="-1">Manage Synced Server Assets <a class="header-anchor" href="#manage-synced-server-assets" aria-label="Permalink to &quot;Manage Synced Server Assets&quot;">​</a></h3><p>Synced assets under a bastion host support these actions:</p><ul><li>Tap a card to connect</li><li>Long-press a card to edit notes</li><li>Long-press a card to add it to favorites</li></ul><h2 id="key-management" tabindex="-1">Key Management <a class="header-anchor" href="#key-management" aria-label="Permalink to &quot;Key Management&quot;">​</a></h2><p>Key Management is used to maintain the SSH keys required for login.</p><ul><li>Tap the lower-right <code>+</code> button to add a new key</li><li>Import key files from local storage</li><li>Use the edit and delete actions shown on each key card</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you manage many hosts, keep favorites, groups, and notes organized first. It makes searching much faster.</p></div>',25)]))}const p=a(i,[["render",n]]);export{u as __pageData,p as default};
